nodes.signature:
role:permission
                            {action : Aksi yang dilakukan: list-roles | check | set | revoke | sync | list-permissions}
                            {--role= : Nama role yang ingin di-cek atau dimodifikasi}
                            {--permission= : Nama permission (bisa multiple, pisahkan dengan koma)}
                            {--guard=web : Guard name (default: web)}
                            {--filter= : Filter permission berdasarkan kata kunci}

laporan:generate 
                            {--month= : Target month (1-12)}
                            {--year= : Target year}
                            {--force : Force generation even if laporan exists}

media:migrate-unit-kerja-structure 
                            {--check : Only analyze current structure without migrating}
                            {--unit-slug=* : Migrate specific unit kerja by slug}
                            {--dry-run : Show what would be done without executing}
                            {--backup : Create backup before migration}
                            {--force : Force migration even with existing target structure}
                            {--disk=all : Target disk for migration (public, s3, all)}

laporan:generate-monthly 
                            {--month= : Month to generate (1-12), defaults to previous month}
                            {--year= : Year to generate, defaults to current year}
                            {--auto-calculate : Automatically calculate from daily reports after generation}

penilaian:media-summary
                            {--details : Show detailed issues}
                            {--pattern : Analyze storage pattern}
                            {--filter= : Filter by unit name}

cache:clear-all
                            {--optimize : Re-optimize after clearing}
                            {--force : Force clear without confirmation}

unit-kerja:sync-folders 
                            {--check : Only check missing folders without creating}
                            {--unit-id=* : Sync specific unit kerja by ID}
                            {--unit-slug=* : Sync specific unit kerja by slug}
                            {--dry-run : Show what would be done without executing}
                            {--force : Force recreate all folders (danger!)}
